var seed = GetInt(parameters, "seed", context.Seed);
var density = GetFloat(parameters, "density", 6.0f);
var intensity = GetFloat(parameters, "intensity", 0.6f);
var color = GetColor(parameters, "color", System.Windows.Media.Color.FromRgb(40, 200, 200));
var lineWidth = GetFloat(parameters, "lineWidth", 0.05f);
var pulse = GetFloat(parameters, "pulse", 0.3f);
var size = context.TileSize;
var result = new PixelBuffer(size, size);
var cR=color.R/255f; var cG=color.G/255f; var cB=color.B/255f;
result.ParallelForEachPixel((x, y) =>
{
    var u = x / (float)size;
    var v = y / (float)size;
    var period = Math.Max(1, size);
    // Distorted voronoi for energy tendrils
    var (pu, pv) = PerturbUv(u * density, v * density, pulse, period, seed);
    TileableVoronoi(pu * size / density, pv * size / density, Math.Max(1, (int)(size / density)), Math.Max(1, (int)density), seed, out var near, out var second, out _, out _);
    var edge = second - near;
    var glow = Math.Clamp(1f - edge / lineWidth, 0f, 1f);
    glow = glow * glow * intensity;
    result.SetPixel(x, y, cR * glow, cG * glow, cB * glow, 1f);
